21→func TestInit_Enabled(t *testing.T) {
22→	// Exporter creation succeeds without a running collector — it only
23→	// fails when it tries to actually send data.
24→	mp, tp, err := Init(context.Background(), Config{
25→		Enabled:     true,
26→		ServiceName: "test-service",
27→		Version:     "v0.0.1-test",
28→		Environment: "test",
29→	})
30→	if err != nil {
31→		t.Fatalf("Init(enabled) error = %v", err)
32→	}
33→	if mp == nil {
34→		t.Error("expected non-nil MeterProvider when enabled")
35→	}
36→	if tp == nil {
37→		t.Error("expected non-nil TracerProvider when enabled")
38→	}
39→
40→	// Clean up to avoid leaking background goroutines.
41→	// Shutdown may fail with connection refused since no collector is running — that's expected.
42→	_ = Shutdown(context.Background(), mp, tp)
43→}
