// Search is the resolver for the search field.
func (r *queryResolver) Search(ctx context.Context, filters []*model.FilterInput, limit *int, offset *int, sort *model.SortInput, userLocation *model.UserLocation, rankingBlend []*model.RankingBlendWeight) (*model.SearchResponse, error) {
	start := time.Now()

	req := search.SearchRequest{}
	filterNames := make([]string, 0, len(filters))
	for _, f := range filters {
		req.Filters = append(req.Filters, search.FilterInput{
			Field: string(f.Field),
			Value: f.Value,
		})
		filterNames = append(filterNames, string(f.Field))
	}
	if limit != nil {
		req.Limit = *limit
	}
	if offset != nil {
		req.Offset = *offset
	}

	// Map UserLocation from GraphQL model to search type.
	if userLocation != nil {
		loc := &search.UserLocation{
			Latitude:  userLocation.Latitude,
			Longitude: userLocation.Longitude,
		}
		if userLocation.State != nil {
			loc.State = *userLocation.State
		}
		req.UserLocation = loc
	}

	// Map SortInput from GraphQL model to search type.
	if sort != nil {
		s := &search.SortInput{
			Field: string(sort.Field),
		}
		if sort.Direction != nil {
			s.Direction = search.SortDirection(*sort.Direction)
		}
		req.Sort = s
	}

	// Map ranking blend weights.
	if len(rankingBlend) > 0 {
		blend := &search.BlendInput{}
		for _, w := range rankingBlend {
			blend.Weights = append(blend.Weights, search.BlendWeight{
				Field:  string(w.Field),
				Weight: w.Weight,
			})
		}
		req.Blend = blend
	}

	slog.DebugContext(ctx, "search: building query",
		"filter_count", len(filters),
		"filter_fields", filterNames,
		"limit", req.Limit,
		"offset", req.Offset,
		"has_user_location", req.UserLocation != nil,
		"has_sort", req.Sort != nil,
	)

	// Validate the request before executing queries.
	authenticated := auth.GetClaims(ctx) != nil
	if errs := search.ValidateRequest(r.Resolver.Search, req, authenticated); len(errs) > 0 {
		e := errs[0]
		if e.Field != "" && e.Field[0] != '_' {
			return nil, fmt.Errorf("search: validation: field %q: %s", e.Field, e.Message)
		}
		return nil, fmt.Errorf("search: validation: %s", e.Message)
	}

	// Count total matching rows (without LIMIT/OFFSET).
	countSQL, countArgs, err := search.BuildCountQuery(r.Resolver.Search, req)
	if err != nil {
		slog.ErrorContext(ctx, "search: failed to build count query",
			"filter_fields", filterNames,
			"error", err,
		)
		return nil, fmt.Errorf("search: build count query: %w", err)
	}
	var total int
	if err := r.DB.QueryRow(ctx, countSQL, countArgs...).Scan(&total); err != nil {
		slog.ErrorContext(ctx, "search: count query failed",
			"filter_fields", filterNames,
			"error", err,
		)
		return nil, fmt.Errorf("search: count query: %w", err)
	}

	// Fetch paginated result rows.
	rowsSQL, rowsArgs, err := search.BuildQuery(r.Resolver.Search, req)
	if err != nil {
		slog.ErrorContext(ctx, "search: failed to build query",
			"filter_fields", filterNames,
			"error", err,
		)
		return nil, fmt.Errorf("search: build query: %w", err)
	}
	rows, err := r.DB.Query(ctx, rowsSQL, rowsArgs...)
	if err != nil {
		slog.ErrorContext(ctx, "search: query execution failed",
			"filter_fields", filterNames,
			"error", err,
		)
		return nil, fmt.Errorf("search: query: %w", err)
	}
	defer rows.Close()

	var results []*model.SearchInstitution
	for rows.Next() {
		var inst model.SearchInstitution
		var rawData map[string]any
		if err := rows.Scan(
			&inst.UnitID, &inst.Name, &inst.City, &inst.State,
			&inst.Latitude, &inst.Longitude,
			&inst.Distance, &inst.MyPrice,
			&rawData, &inst.BlendScore,
		); err != nil {
			slog.ErrorContext(ctx, "search: row scan failed", "error", err)
			return nil, fmt.Errorf("search: scan: %w", err)
		}
		if rawData != nil {
			inst.LocationDetails = extractLocation(rawData)
			inst.Academics = extractAcademics(rawData)
			inst.Cost = extractCost(rawData)
			inst.Outcomes = extractOutcomes(rawData)
			inst.Rankings = extractRankings(rawData)
			inst.Admissions = extractAdmissions(rawData)
			inst.Athletics = extractAthletics(rawData)
			inst.Climate = extractClimate(rawData)
			inst.Culture = extractCulture(rawData)
			inst.Demographics = extractDemographics(rawData)
			inst.Meta = extractMeta(rawData)
		}
		results = append(results, &inst)
	}
	if err := rows.Err(); err != nil {
		slog.ErrorContext(ctx, "search: row iteration error", "error", err)
		return nil, fmt.Errorf("search: rows: %w", err)
	}

	effectiveLimit := search.DefaultLimit
	if limit != nil && *limit > 0 {
		effectiveLimit = *limit
	}
	if effectiveLimit > search.MaxLimit {
		effectiveLimit = search.MaxLimit
	}
	effectiveOffset := 0
	if offset != nil {
		effectiveOffset = *offset
	}
	if effectiveOffset+effectiveLimit > search.MaxLimit {
		effectiveOffset = search.MaxLimit - effectiveLimit
		if effectiveOffset < 0 {
			effectiveOffset = 0
		}
	}

	duration := time.Since(start)
	slog.DebugContext(ctx, "search: completed",
		"filter_count", len(filters),
		"filter_fields", filterNames,
		"total_results", total,
		"returned_results", len(results),
		"limit", effectiveLimit,
		"offset", effectiveOffset,
		"duration_ms", duration.Milliseconds(),
	)

	return &model.SearchResponse{
		Results: results,
		Total:   total,
		Limit:   effectiveLimit,
		Offset:  effectiveOffset,
	}, nil
}

