	sdklog "go.opentelemetry.io/otel/sdk/log"
	sdkmetric "go.opentelemetry.io/otel/sdk/metric"
	"go.opentelemetry.io/otel/sdk/resource"
	sdktrace "go.opentelemetry.io/otel/sdk/trace"
	semconv "go.opentelemetry.io/otel/semconv/v1.26.0"
)

// Config holds the settings for OpenTelemetry initialization.
type Config struct {
	Enabled     bool
	ServiceName string
	Version     string
	Environment string

	// PostHogAPIKey enables the OTel logs pipeline to PostHog when non-empty.
	// Logs are sent independently of whether traces/metrics are Enabled.
	PostHogAPIKey string

	// PostHogHost is the PostHog instance host (e.g. "https://us.i.posthog.com").
	// Defaults to "https://us.i.posthog.com" when empty.
	PostHogHost string
}

// Providers holds all OTel provider references returned by Init.
type Providers struct {
	Meter  *sdkmetric.MeterProvider
	Tracer *sdktrace.TracerProvider
	Logger *sdklog.LoggerProvider
}

// Init creates and registers OpenTelemetry providers.
//
// Traces and metrics are created when cfg.Enabled is true, using standard
// OTel environment variables for OTLP connection details.
//
// The log provider is created when cfg.PostHogAPIKey is non-empty, regardless
// of cfg.Enabled. It exports logs via OTLP/HTTP to PostHog's logs endpoint.
func Init(ctx context.Context, cfg Config) (*Providers, error) {
	p := &Providers{}

	res, err := resource.New(ctx,
		resource.WithAttributes(
			semconv.ServiceName(cfg.ServiceName),
			semconv.ServiceVersion(cfg.Version),
			semconv.DeploymentEnvironment(cfg.Environment),
		),
		resource.WithTelemetrySDK(),
		resource.WithHost(),
	)
	if err != nil {
		return nil, fmt.Errorf("otel: build resource: %w", err)
	}

	// Traces & metrics (opt-in via OTEL_ENABLED)
	if cfg.Enabled {
		if err := initMetricsAndTraces(ctx, res, p); err != nil {
			return nil, err
		}
	}

	// Logs to PostHog (opt-in via POSTHOG_API_KEY)
	if cfg.PostHogAPIKey != "" {
		lp, err := initLogProvider(ctx, res, cfg)
		if err != nil {
			return nil, err
		}
		p.Logger = lp
	}

	return p, nil
}

func initMetricsAndTraces(ctx context.Context, res *resource.Resource, p *Providers) error {
	metricExp, err := otlpmetrichttp.New(ctx)
	if err != nil {
		return fmt.Errorf("otel: create metric exporter: %w", err)
	}

	p.Meter = sdkmetric.NewMeterProvider(
		sdkmetric.WithResource(res),
		sdkmetric.WithReader(sdkmetric.NewPeriodicReader(metricExp)),
	)
	otel.SetMeterProvider(p.Meter)

	traceExp, err := otlptracehttp.New(ctx)
	if err != nil {
		return fmt.Errorf("otel: create trace exporter: %w", err)
	}

	p.Tracer = sdktrace.NewTracerProvider(
		sdktrace.WithResource(res),
		sdktrace.WithBatcher(traceExp),
	)
	otel.SetTracerProvider(p.Tracer)
	otel.SetTextMapPropagator(propagation.NewCompositeTextMapPropagator(
		propagation.TraceContext{},
		propagation.Baggage{},
	))

	return nil
}

const defaultPostHogHost = "https://us.i.posthog.com"

func initLogProvider(ctx context.Context, res *resource.Resource, cfg Config) (*sdklog.LoggerProvider, error) {
	host := cfg.PostHogHost
	if host == "" {
		host = defaultPostHogHost
	}

	u, err := url.Parse(host)
	if err != nil {
		return nil, fmt.Errorf("otel: parse PostHog host %q: %w", host, err)
	}

	logExp, err := otlploghttp.New(ctx,
		otlploghttp.WithEndpoint(u.Host),
		otlploghttp.WithURLPath("/i/v1/logs"),
		otlploghttp.WithHeaders(map[string]string{
			"Authorization": "Bearer " + cfg.PostHogAPIKey,
		}),
	)
	if err != nil {
		return nil, fmt.Errorf("otel: create log exporter: %w", err)
	}

	lp := sdklog.NewLoggerProvider(
		sdklog.WithResource(res),
		sdklog.WithProcessor(sdklog.NewBatchProcessor(logExp)),
	)

	return lp, nil
}

// Shutdown gracefully flushes and shuts down the meter and tracer providers.
// It is nil-safe — passing nil providers is a no-op.
func Shutdown(ctx context.Context, mp *sdkmetric.MeterProvider, tp *sdktrace.TracerProvider) error {
	var firstErr error
	if tp != nil {
		if err := tp.Shutdown(ctx); err != nil && firstErr == nil {
			firstErr = fmt.Errorf("otel: shutdown tracer: %w", err)
		}
	}
	if mp != nil {
		if err := mp.Shutdown(ctx); err != nil && firstErr == nil {
			firstErr = fmt.Errorf("otel: shutdown meter: %w", err)
		}
	}
	return firstErr
}

