	})
	if err != nil {
		t.Fatalf("Init() error = %v", err)
	}
	if p.Logger == nil {
		t.Fatal("expected non-nil LoggerProvider with custom host")
	}
	_ = p.Logger.Shutdown(context.Background())
}

func TestShutdown_NilSafe(t *testing.T) {
	if err := Shutdown(context.Background(), nil); err != nil {
		t.Errorf("Shutdown(nil) error = %v", err)
	}

	if err := Shutdown(context.Background(), &Providers{}); err != nil {
		t.Errorf("Shutdown(empty) error = %v", err)
	}
}

func TestNewSlogHandler_NilProviderReturnsNil(t *testing.T) {
	h := NewSlogHandler(nil)
	if h != nil {
		t.Error("expected nil handler when LoggerProvider is nil")
	}
}

func TestNewSlogHandler_NonNilProvider(t *testing.T) {
	p, err := Init(context.Background(), Config{
		PostHogAPIKey: "phc_test_key",
	})
	if err != nil {
		t.Fatalf("Init() error = %v", err)
	}
	defer func() { _ = p.Logger.Shutdown(context.Background()) }()

	h := NewSlogHandler(p.Logger)
	if h == nil {
		t.Error("expected non-nil handler when LoggerProvider is set")
	}
}

