package otel

import (
	"context"
	"testing"
)

func TestInit_Disabled(t *testing.T) {
	mp, tp, err := Init(context.Background(), Config{Enabled: false})
	if err != nil {
		t.Fatalf("Init(disabled) error = %v", err)
	}
	if mp != nil {
		t.Error("expected nil MeterProvider when disabled")
	}
	if tp != nil {
		t.Error("expected nil TracerProvider when disabled")
	}
}

func TestInit_Enabled(t *testing.T) {
	// Exporter creation succeeds without a running collector — it only
	// fails when it tries to actually send data.
	mp, tp, err := Init(context.Background(), Config{
		Enabled:     true,
		ServiceName: "test-service",
		Version:     "v0.0.1-test",
		Environment: "test",
	})
	if err != nil {
		t.Fatalf("Init(enabled) error = %v", err)
	}
	if mp == nil {
		t.Error("expected non-nil MeterProvider when enabled")
	}
	if tp == nil {
		t.Error("expected non-nil TracerProvider when enabled")
	}

	// Clean up to avoid leaking background goroutines.
	// Shutdown may fail with connection refused since no collector is running — that's expected.
	_ = Shutdown(context.Background(), mp, tp)
}

func TestShutdown_NilProviders(t *testing.T) {
	// Must not panic.
	if err := Shutdown(context.Background(), nil, nil); err != nil {
		t.Errorf("Shutdown(nil, nil) error = %v", err)
	}
}

func TestShutdown_WithProviders(t *testing.T) {
	mp, tp, err := Init(context.Background(), Config{
		Enabled:     true,
		ServiceName: "test-shutdown",
		Version:     "v0.0.1",
		Environment: "test",
	})
	if err != nil {
		t.Fatalf("Init error = %v", err)
	}
	// Shutdown flushes to the OTLP endpoint which isn't running in tests.
	// Connection-refused errors are expected and not a test failure.
	_ = Shutdown(context.Background(), mp, tp)
}

package otel

import (
	"context"
	"net/http"
	"net/http/httptest"
	"testing"

	"go.opentelemetry.io/otel/sdk/trace/tracetest"

	sdktrace "go.opentelemetry.io/otel/sdk/trace"

	"go.opentelemetry.io/otel"
)

func TestMiddleware_CreatesSpan(t *testing.T) {
	// Set up an in-memory span exporter to capture spans.
	exporter := tracetest.NewInMemoryExporter()
	tp := sdktrace.NewTracerProvider(sdktrace.WithSyncer(exporter))
	otel.SetTracerProvider(tp)
	defer func() { _ = tp.Shutdown(context.Background()) }()

	handler := Middleware("test-op")(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
	}))

	req := httptest.NewRequest(http.MethodGet, "/test", nil)
	rec := httptest.NewRecorder()
	handler.ServeHTTP(rec, req)

	// Force flush to ensure spans are exported.
	_ = tp.ForceFlush(context.Background())

	spans := exporter.GetSpans()
	if len(spans) == 0 {
		t.Fatal("expected at least one span, got none")
	}
}

func TestMiddleware_CapturesStatusCode(t *testing.T) {
	exporter := tracetest.NewInMemoryExporter()
	tp := sdktrace.NewTracerProvider(sdktrace.WithSyncer(exporter))
	otel.SetTracerProvider(tp)
	defer func() { _ = tp.Shutdown(context.Background()) }()

	tests := []struct {
		name   string
		status int
	}{
		{"200 OK", http.StatusOK},
		{"404 Not Found", http.StatusNotFound},
		{"500 Internal Server Error", http.StatusInternalServerError},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			exporter.Reset()

			handler := Middleware("test-op")(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
				w.WriteHeader(tt.status)
			}))

			req := httptest.NewRequest(http.MethodGet, "/test", nil)
			rec := httptest.NewRecorder()
			handler.ServeHTTP(rec, req)

			if rec.Code != tt.status {
				t.Errorf("expected status %d, got %d", tt.status, rec.Code)
			}

			_ = tp.ForceFlush(context.Background())

			spans := exporter.GetSpans()
			if len(spans) == 0 {
				t.Fatal("expected at least one span")
			}
		})
	}
}

