package otel

import (
	"bytes"
	"context"
	"log/slog"
	"testing"
)

func TestFanoutHandler_DispatchesToAll(t *testing.T) {
	var buf1, buf2 bytes.Buffer
	h1 := slog.NewTextHandler(&buf1, &slog.HandlerOptions{Level: slog.LevelInfo})
	h2 := slog.NewTextHandler(&buf2, &slog.HandlerOptions{Level: slog.LevelInfo})

	fanout := NewFanoutHandler(h1, h2)
	logger := slog.New(fanout)
	logger.Info("hello", "key", "val")

	if buf1.Len() == 0 {
		t.Error("handler 1 received no output")
	}
	if buf2.Len() == 0 {
		t.Error("handler 2 received no output")
	}
}

func TestFanoutHandler_SkipsNilHandlers(t *testing.T) {
	var buf bytes.Buffer
	h := slog.NewTextHandler(&buf, &slog.HandlerOptions{Level: slog.LevelInfo})

	fanout := NewFanoutHandler(nil, h, nil)
	logger := slog.New(fanout)
	logger.Info("test")

	if buf.Len() == 0 {
		t.Error("non-nil handler received no output")
	}
}

func TestFanoutHandler_EnabledRespectsLevels(t *testing.T) {
	h1 := slog.NewTextHandler(&bytes.Buffer{}, &slog.HandlerOptions{Level: slog.LevelError})
	h2 := slog.NewTextHandler(&bytes.Buffer{}, &slog.HandlerOptions{Level: slog.LevelDebug})

	fanout := NewFanoutHandler(h1, h2)

	// Debug is enabled because h2 accepts it.
	if !fanout.Enabled(context.Background(), slog.LevelDebug) {
		t.Error("expected Enabled(Debug) = true when one handler accepts Debug")
	}

	// Both accept Error.
	if !fanout.Enabled(context.Background(), slog.LevelError) {
		t.Error("expected Enabled(Error) = true")
	}
}

func TestFanoutHandler_WithAttrs(t *testing.T) {
	var buf bytes.Buffer
	h := slog.NewTextHandler(&buf, &slog.HandlerOptions{Level: slog.LevelInfo})

	fanout := NewFanoutHandler(h)
	withAttrs := fanout.WithAttrs([]slog.Attr{slog.String("component", "test")})

	logger := slog.New(withAttrs)
	logger.Info("msg")

	if !bytes.Contains(buf.Bytes(), []byte("component=test")) {
		t.Errorf("expected attrs in output, got: %s", buf.String())
	}
}

func TestFanoutHandler_WithGroup(t *testing.T) {
	var buf bytes.Buffer
	h := slog.NewTextHandler(&buf, &slog.HandlerOptions{Level: slog.LevelInfo})

	fanout := NewFanoutHandler(h)
	withGroup := fanout.WithGroup("grp")

	logger := slog.New(withGroup)
	logger.Info("msg", "k", "v")

	if !bytes.Contains(buf.Bytes(), []byte("grp.k=v")) {
		t.Errorf("expected group prefix in output, got: %s", buf.String())
	}
}

func TestFanoutHandler_Empty(t *testing.T) {
	fanout := NewFanoutHandler()
	if fanout.Enabled(context.Background(), slog.LevelInfo) {
		t.Error("empty fanout should not be enabled for any level")
	}
}

